 Begin TimeMap 	# Conversion between time coordinate systems
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Ntime = 2 	# Number of conversion steps
    Time1 = "MJDTOJD" 	# Convert MJD to JD
    Time1a = 0 	# MJD offset
    Time1b = 2400000.5 	# JD offset
    Time1c = 0 	# Combined offset
    Time2 = "JDTOMJD" 	# Convert JD to MJD
    Time2a = 2400000.5 	# JD offset
    Time2b = 0 	# MJD offset
    Time2c = 0 	# Combined offset
 End TimeMap
